	$param="wrap-selection"
	prefix={{{ [{$:/config/WLCM/inline/default}get[prefix]addsuffix[ ]] ~[[/° ]] }}}
	suffix={{{ [{$:/config/WLCM/inline/default}get[suffix]] ~[[°/]]}}}
/>
</$list>

<$action-deletetiddler $tiddler="$:/state/EditorToolbarDropdown--124516744"/>
\end

