		{{$:/core/images/options-button}}
	</$button>
</span>
<$wl-keyboard key=<<keys>> actions=<<actionKey>> >
	<$list filter=<<range>> variable=key>
		<$tiddler tiddler={{{[{$:/config/WLCM/InlineSet/selected}getindex<key>has[title]else[Error - Tiddler doesn't exist]]}}}>
			-<<key>>-&nbsp;:&nbsp;
			<span class="wltc-snippet ">
			<$button class="tc-btn-invisible" actions=<<actionClick>> >
				<$view field="caption">&nbsp;<$transclude field=title/></$view>
			</$button>
			</span><br>
		</$tiddler>
	</$list><br>
	Enter:&nbsp;<$edit-text tiddler="$:/config/WLCM/inline/default" placeholder="- hit key -" tag=input disabled=yesX focus />
</$wl-keyboard>
</$set>
</$set>
