<$action-createtiddler $basetitle="$:/config/wikilabs/custom-markup/icons/glyphs/active" $overwrite="yes" $template={{{ [all[shadows+tiddlers]tag[$:/tags/CustomMarkup/Marker]field:open{$:/config/edit/linePrefix!!id}get[marker-icon]] }}} />
\end
