title: $:/plugins/wikilabs/custom-markup/editor/operations/text/toggle-tick.js
type: application/javascript
module-type: texteditoroperation

Text editor operation to add a prefix to the selected lines

\*/

/*jslint node: true, browser: true */
/*global $tw:false exports:false */
"use strict";

exports["toggle-tick"] = function(event,operation) {
	var targetCount = parseInt(event.paramObject.count + "",10);
	// Cut just past the preceding line break, or the start of the text
	operation.cutStart = $tw.utils.findPrecedingLineBreak(operation.text,operation.selStart);
	// Cut to just past the following line break, or to the end of the text
	operation.cutEnd = $tw.utils.findFollowingLineBreak(operation.text,operation.selEnd);
	// Compose the required prefix
	var prefix = $tw.utils.repeat(event.paramObject.character,targetCount);
	// Process each line
	var lines,
		text = operation.text.substring(operation.cutStart,operation.cutEnd);
	if (text === "\n" || text === "\r\n") {
		if (operation.cutEnd < operation.cutStart) {
			var x = operation.cutEnd;
			operation.cutEnd = operation.cutStart
			operation.cutStart = x;
		}
		lines = [""]; // only 1 line should be used
	} else {
		lines = text.split(/\r?\n/mg);
	}
	$tw.utils.each(lines,function(line,index) {
		// Remove and count any existing prefix characters
		var addPrefix = true;
		var fragments = line.split(" ");
		if (fragments[0] === event.paramObject.character) {
			line = fragments.slice(1).join(" ");
			addPrefix = false
		} else {
			line = fragments.join(" ");
		}
		// Remove any whitespace
		while(line.charAt(0) === " ") {
			line = line.substring(1);
		}
		// We're done if we removed the exact required prefix, otherwise add it
		if(addPrefix) {
			// Apply the prefix
			if (event.paramObject && event.paramObject.force === "yes") {
				line = prefix + " " + line;
			} else {
				line = (line === "") ? line : prefix + " " + line;
			}
		}
		// Save the modified line
		lines[index] = line;
	}); 
	// Stitch the replacement text together and set the selection
	operation.replacement = lines.join("\n");
	if(lines.length === 1) {
		operation.newSelStart = operation.cutStart + operation.replacement.length;
		operation.newSelEnd = operation.newSelStart;
	} else {
		operation.newSelStart = operation.cutStart;
		operation.newSelEnd = operation.newSelStart + operation.replacement.length;
	}
};

","type":"application/javascript","module-type":"texteditoroperation"},"$:/plugins/wikilabs/custom-markup/filteroperators/cm-active-markers.js":{"title":"$:/plugins/wikilabs/custom-markup/filteroperators/cm-active-markers.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/filteroperators/cm-active-markers.js
type: application/javascript
module-type: filteroperator

Filter operator returning marker tiddler titles active in the source
tiddler's vocabulary. Usage: `[<currentTiddler>cm-active-markers[block]]`.

Operand selects marker kinds:
  block       glyph + glyph-level (line-prefix markers)
  inline      inline-pair
  word        word markers only
  glyph       glyph + glyph-level (alias of block)
  (empty)     all kinds

Vocabularies come from the source tiddler's `type` field, parsed for
`text/vnd.tiddlywiki;vocab=A,B`. With no `;vocab=` parameter, falls back
to `Default`.

\*/

"use strict";

exports["cm-active-markers"] = function(source, operator, options) {
	var wiki = options.wiki;
	var kindOperand = operator.operand || "";
	var results = [];
	var seen = Object.create(null);
	var hadInput = false;

	var collect = function(typeStr) {
		var markerTags = activeMarkerTags(wiki, typeStr);
		if(markerTags.length === 0) { return; }
		var markers = wiki.filterTiddlers(
			"[all[shadows+tiddlers]tag[$:/tags/CustomMarkup/Marker]]"
		);
		markers.forEach(function(mt) {
			if(seen[mt]) { return; }
			var m = wiki.getTiddler(mt);
			if(!m) { return; }
			if(!matchesKind(m.fields.kind, kindOperand)) { return; }
			var mTags = m.fields.tags || [];
			var isActive = mTags.some(function(tg) {
				return markerTags.indexOf(tg) !== -1;
			});
			if(isActive) {
				seen[mt] = true;
				results.push(mt);
			}
		});
	};

	source(function(tiddler) {
		hadInput = true;
		collect((tiddler && tiddler.fields && tiddler.fields.type) || "");
	});

	// Empty source (e.g. $:/HistoryList not yet populated) falls back to
	// Default vocab so the editor toolbar still shows usable markers.
	if(!hadInput) {
		collect("");
	}
	return results;
};

function activeMarkerTags(wiki, typeStr) {
	var match = /;\s*vocab\s*=\s*([^;]+)/.exec(typeStr);
	var vocabNames = match
		? match[1].split(",").map(function(s) { return s.trim(); }).filter(Boolean)
		: ["Default"];
	var tags = [];
	vocabNames.forEach(function(name) {
		var vocabTitle = "vocab/" + name.toLowerCase();
		var meta = wiki.getTiddler(vocabTitle);
		if(!meta) { return; }
		var metaTags = meta.fields.tags;
		if(!metaTags || metaTags.indexOf("$:/tags/CustomMarkup/Vocabulary") === -1) { return; }
		tags.push(vocabTitle);
	});
	return tags;
}

function matchesKind(kind, operand) {
	switch(operand) {
		case "":
			return true;
		case "block":
		case "glyph":
			return kind === "glyph" || kind === "glyph-level";
		case "inline":
			return kind === "inline-pair";
		case "word":
			return kind === "word";
		default:
			return kind === operand;
	}
}
