title: $:/plugins/wikilabs/custom-markup/wl-radio-widget.js
type: application/javascript
module-type: widget-subclass
\*/

/*jslint node: true, browser: true */
/*global $tw: false */
"use strict";

exports.baseClass = "radio";
exports.name = "wl-radio";

exports.constructor = function(parseTreeNode,options) {
	this.initialise(parseTreeNode,options);
}
exports.prototype = {};

exports.prototype.handleChangeEvent = function(event) {
	var variables = Object.create(null);
	if(this.inputDomNode.checked) {
		this.setValue();
	}
	// Trigger actions. Use variables = {key:value, key:value ...}
	if(this.radioActions) {
		$tw.utils.each(this.attributes,function(val,key) {
			if (key.substring(0,4) === "usr-") {
				variables[key] = "" + val;
			} else {
				variables["__" + key + "__"] = "" + val;
			}
		});
		// "tiddler" and/or "field" parameter may be missing in the widget call. See radio widget .execute() 
		variables = $tw.utils.extend(variables, {"__tiddler__": this.radioTitle,"__field__": this.radioField});
		this.invokeActionString(this.radioActions,this,event,variables);
	}
}
","type":"application/javascript","module-type":"widget-subclass"},"$:/plugins/wikilabs/custom-markup/wikirules/front-matter.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/front-matter.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/front-matter.js
type: application/javascript
module-type: wikirule

YAML front-matter block. Fires only at parser.pos === 0 and only when
an activated vocab meta tiddler declares `front-matter: yes`. Reads
lines from the top of the source until a blank line or a `===` (or
longer) separator and hands the captured text to the YAML library;
the resulting object becomes one row per top-level key in the rendered
`<div class="wltc-front-matter">`.

The capture phase accepts both `Key: Value` lines and continuation
lines that begin with whitespace, so YAML's spec-compliant multi-line
values (Fountain title-page `Notes:\n\tline\n\tline`) survive into the
parser. The first line must still look like a top-level `Key:` so we
don't grab arbitrary prose.

Rendering keeps the previous structure: each top-level pair produces a
`<div class="wltc-front-matter-row" data-key="<Key>">` with a hidden
key span and a value span. Scalar values render directly; arrays
render as comma-joined strings; nested maps fall back to a JSON-ish
inline form (the simple title-page case rarely needs more).

\*/

"use strict";

var yaml = require("$:/plugins/wikilabs/custom-markup/yaml.js");

// Match a top-level `Key:` line. Key must start with an uppercase
// letter so we don't catch random `word: thing` mid-sentence; allow
// word chars, hyphens, and embedded single spaces so multi-word keys
// like `Draft date:` survive (common in Fountain title pages). The
// trailing assertion requires whitespace or end-of-line after the
// colon to avoid matching URLs (`https:` ...).
var KEY_LINE_RE = /^[A-Z][\w-]*(?:[ ][\w-]+)*:(?:[ \t]|$)/;
var SEPARATOR_RE = /^={3,}[ \t]*$/;

exports.name = "frontmatter";
exports.types = {block: true};

exports.init = function(parser) {
	this.parser = parser;
	if(!parser.cmRegistry) {
		parser.cmRegistry = new $tw.utils.CmRegistry(parser.wiki);
		parser.cmRegistry.loadAllMarkers();
		parser.cmRegistry.loadGlobalPragmas();
		parser.cmRegistry.activateFromTypeField(parser.type);
		parser.cmRegistry.applyAmendRules(parser);
	}
};

exports.findNextMatch = function(startPos) {
	if(startPos !== 0) { return undefined; }
	if(!this.parser.cmRegistry.hasFrontMatter()) { return undefined; }
	var firstLine = readLine(this.parser.source, 0);
	if(!KEY_LINE_RE.test(firstLine.text)) { return undefined; }
	this.match = [firstLine.text];
	return 0;
};

exports.parse = function() {
	var source = this.parser.source;
	var pos = 0;
	var captured = [];
	while(pos < source.length) {
		var line = readLine(source, pos);
		if(line.text === "" || /^\s*$/.test(line.text)) {
			pos = line.nextPos;
			break;
		}
		if(SEPARATOR_RE.test(line.text)) {
			pos = line.nextPos;
			break;
		}
		// Accept top-level Key: lines, or continuation lines that begin
		// with whitespace (YAML's spec for multi-line scalar values).
		// Anything else ends the block without consuming the offending
		// line, so the next rule can handle it.
		if(!KEY_LINE_RE.test(line.text) && !/^[ \t]/.test(line.text)) {
			break;
		}
		captured.push(line.text);
		pos = line.nextPos;
	}
	this.parser.pos = pos;
	if(captured.length === 0) { return []; }
	var parsed;
	try {
		parsed = yaml.load(captured.join("\n"));
	} catch(e) {
		// If YAML parsing fails, treat the block as not-front-matter:
		// rewind the parser to before the block so the lines render via
		// regular rules.
		this.parser.pos = 0;
		return [];
	}
	if(!parsed || typeof parsed !== "object" || Array.isArray(parsed)) {
		this.parser.pos = 0;
		return [];
	}
	var keys = Object.keys(parsed);
	if(keys.length === 0) { return []; }
	var children = keys.map(function(key) {
		var value = parsed[key];
		return {
			type: "element", tag: "div",
			attributes: {
				"class": {type: "string", value: "wltc-front-matter-row"},
				"data-key": {type: "string", value: key}
			},
			children: [
				{
					type: "element", tag: "span",
					attributes: {"class": {type: "string", value: "wltc-front-matter-key"}},
					children: [{type: "text", text: key + ": "}]
				},
				{
					type: "element", tag: "span",
					attributes: {"class": {type: "string", value: "wltc-front-matter-value"}},
					children: [{type: "text", text: formatValue(value)}]
				}
			]
		};
	});
	return [{
		type: "element", tag: "div",
		attributes: {"class": {type: "string", value: "wltc-front-matter"}},
		children: children
	}];
};

// Coerce a parsed YAML value into a single display string. The common
// title-page cases are strings; arrays show as comma-joined; anything
// else (object, null) falls back to JSON so the user at least sees the
// data rather than `[object Object]`.
function formatValue(value) {
	if(value === null || value === undefined) { return ""; }
	if(typeof value === "string") { return value; }
	if(typeof value === "number" || typeof value === "boolean") {
		return String(value);
	}
	if(Array.isArray(value)) {
		return value.map(formatValue).join(", ");
	}
	try {
		return JSON.stringify(value);
	} catch(e) {
		return String(value);
	}
}

function readLine(source, pos) {
	var nlIdx = source.indexOf("\n", pos);
	if(nlIdx === -1) {
		return {text: source.substring(pos), nextPos: source.length};
	}
	var text = source.substring(pos, nlIdx);
	if(text.charAt(text.length - 1) === "\r") {
		text = text.substring(0, text.length - 1);
	}
	return {text: text, nextPos: nlIdx + 1};
}
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/markdown-newline.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/markdown-newline.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/markdown-newline.js
type: application/javascript
module-type: wikirule

Markdown-style newline handling: every intra-paragraph `\n` (or `\r\n`)
emits a `<br>`. Blank-line paragraph breaks already work via TW's block
parser, which terminates the inline run at `\n\n` before this rule can
see the second newline — so this rule only fires on single newlines
inside a paragraph, never on the boundary between paragraphs.

Fires only when the markdown vocabulary is active for the tiddler being
parsed.

\*/

"use strict";

exports.name = "markdown-newline";
exports.types = {inline: true};

var NL_RE = /\r?\n/g;

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = NL_RE;
	if(!parser.cmRegistry) {
		parser.cmRegistry = new $tw.utils.CmRegistry(parser.wiki);
		parser.cmRegistry.loadAllMarkers();
		parser.cmRegistry.loadGlobalPragmas();
		parser.cmRegistry.activateFromTypeField(parser.type);
		parser.cmRegistry.applyAmendRules(parser);
	}
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.isActiveVocab("vocab/markdown")) {
		return undefined;
	}
	var regex = new RegExp(NL_RE.source, "g");
	regex.lastIndex = startPos;
	var match = regex.exec(this.parser.source);
	if(!match) { return undefined; }
	this.match = match;
	return match.index;
};

exports.parse = function() {
	this.parser.pos = this.match.index + this.match[0].length;
	return [{type: "element", tag: "br"}];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/markdown-table.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/markdown-table.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/markdown-table.js
type: application/javascript
module-type: wikirule

Markdown-style table block rule. Fires only when the markdown vocabulary
is active for the tiddler being parsed.

Recognises pipe-syntax tables with a required separator row:

```
| Header 1 | Header 2 | Header 3 |
|----------|:--------:|---------:|
| left     | centre   | right    |
| cell     | cell     | cell     |
```

Alignment derives from the separator row's colons: `:-` left,
`:-:` centre, `-:` right, plain `-` defaults to left. A blank line or any
line not starting with `|` ends the table. Cells are emitted as plain
text in v1; inline emphasis inside cells is a future enhancement.

\*/

"use strict";

exports.name = "markdown-table";
exports.types = {block: true};

// Match a header row immediately followed by a separator row. The
// separator constraint is what distinguishes a real markdown table from
// any other line that happens to contain pipes.
var TABLE_RE = /^[ \t]*\|[^\r\n]+\|[ \t]*\r?\n[ \t]*\|(?:[ \t]*:?-+:?[ \t]*\|)+[ \t]*(?:\r?\n|$)/mg;
var ROW_RE = /^[ \t]*\|([^\r\n]*?)\|[ \t]*(\r?\n|$)/mg;

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = TABLE_RE;
	if(!parser.cmRegistry) {
		parser.cmRegistry = new $tw.utils.CmRegistry(parser.wiki);
		parser.cmRegistry.loadAllMarkers();
		parser.cmRegistry.loadGlobalPragmas();
		parser.cmRegistry.activateFromTypeField(parser.type);
		parser.cmRegistry.applyAmendRules(parser);
	}
};

exports.findNextMatch = function(startPos) {
	if(!this.parser.cmRegistry || !this.parser.cmRegistry.isActiveVocab("vocab/markdown")) {
		return undefined;
	}
	var regex = new RegExp(TABLE_RE.source, "mg");
	regex.lastIndex = startPos;
	var match = regex.exec(this.parser.source);
	if(!match) { return undefined; }
	this.match = match;
	return match.index;
};

exports.parse = function() {
	var parser = this.parser;
	var headerCells = readInlineRow(parser);
	if(!headerCells) { return [textFallback(parser)]; }
	var separatorText = readPlainRow(parser);
	if(separatorText === null) { return [textFallback(parser)]; }
	var alignments = separatorText.split("|").map(function(c) {
		return c.replace(/^[ \t]+|[ \t]+$/g, "");
	}).map(parseAlignment);

	var dataRows = [];
	while(parser.pos < parser.source.length) {
		var saved = parser.pos;
		var cells = readInlineRow(parser);
		if(!cells) { parser.pos = saved; break; }
		dataRows.push(cells);
	}

	return [buildTable(headerCells, dataRows, alignments)];
};

// Read one row as plain text (used for the separator). Returns the inner
// content (between first and last `|`), advances parser.pos past the
// trailing newline. Null if not a pipe row.
function readPlainRow(parser) {
	var regex = new RegExp(ROW_RE.source, "mg");
	regex.lastIndex = parser.pos;
	var match = regex.exec(parser.source);
	if(!match || match.index !== parser.pos) { return null; }
	parser.pos = match.index + match[0].length;
	return match[1];
}

// Read one row with each cell parsed as an inline run, so emphasis
// markers inside cells (e.g. `*italic*`, `` `code` ``) fire. Advances
// parser.pos past the trailing newline. Null if not a pipe row.
function readInlineRow(parser) {
	var src = parser.source;
	var startPos = parser.pos;
	// Find row extent: from current pos to end-of-line.
	var nlIdx = src.indexOf("\n", startPos);
	if(nlIdx === -1) { nlIdx = src.length; }
	// Trim trailing whitespace (including any \r before \n).
	var rowEnd = nlIdx;
	while(rowEnd > startPos && /[ \t\r]/.test(src.charAt(rowEnd - 1))) { rowEnd--; }
	// Row must start (after optional indent) and end with `|`.
	var probe = startPos;
	while(probe < rowEnd && /[ \t]/.test(src.charAt(probe))) { probe++; }
	if(src.charAt(probe) !== "|" || src.charAt(rowEnd - 1) !== "|") { return null; }

	parser.pos = probe + 1; // past the opening `|`
	var cells = [];
	while(parser.pos < rowEnd - 1) {
		// Trim leading whitespace inside the cell.
		while(parser.pos < rowEnd - 1 && /[ \t]/.test(src.charAt(parser.pos))) { parser.pos++; }
		// Parse inline content until the next `|` (or end of row).
		var cellTerm = /\|/g;
		var children = parser.parseInlineRun(cellTerm);
		trimTrailingWhitespace(children);
		cells.push(children);
		// Step past the `|` separator.
		if(parser.pos < rowEnd && src.charAt(parser.pos) === "|") { parser.pos++; }
		else { break; }
	}
	// Advance past the closing `|` (if not already) and the newline.
	parser.pos = nlIdx < src.length ? nlIdx + 1 : nlIdx;
	return cells;
}

function trimTrailingWhitespace(children) {
	if(children.length === 0) { return; }
	var last = children[children.length - 1];
	if(last && last.type === "text" && typeof last.text === "string") {
		last.text = last.text.replace(/[ \t]+$/, "");
		if(last.text === "") { children.pop(); }
	}
}

// Parse one separator cell like "---", ":---", "---:", ":---:" into
// "left" / "centre" / "right". Anything else defaults to "left".
function parseAlignment(cell) {
	var trimmed = cell.replace(/^[ \t]+|[ \t]+$/g, "");
	var leadsColon = trimmed.charAt(0) === ":";
	var trailsColon = trimmed.charAt(trimmed.length - 1) === ":";
	if(leadsColon && trailsColon) { return "center"; }
	if(trailsColon) { return "right"; }
	return "left";
}

function buildTable(headerCells, dataRows, alignments) {
	function cellNode(tag, children, align) {
		var attrs = {};
		if(align && align !== "left") {
			attrs.style = {type: "string", value: "text-align:" + align};
		}
		return {
			type: "element",
			tag: tag,
			attributes: attrs,
			children: children
		};
	}
	function rowNode(cells, tag) {
		return {
			type: "element",
			tag: "tr",
			children: cells.map(function(c, i) {
				return cellNode(tag, c, alignments[i] || "left");
			})
		};
	}
	return {
		type: "element",
		tag: "table",
		children: [
			{
				type: "element",
				tag: "thead",
				children: [rowNode(headerCells, "th")]
			},
			{
				type: "element",
				tag: "tbody",
				children: dataRows.map(function(r) { return rowNode(r, "td"); })
			}
		]
	};
}

// Last-resort fallback used when findNextMatch matched a position but
// parse() couldn't read a valid header/separator pair (shouldn't happen
// with our tight regex, but defends against future regex drift).
function textFallback(parser) {
	var nlIdx = parser.source.indexOf("\n", parser.pos);
	if(nlIdx === -1) { nlIdx = parser.source.length; }
	var text = parser.source.substring(parser.pos, nlIdx);
	parser.pos = nlIdx + 1;
	return {type: "text", text: text};
}
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/marker-block.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/marker-block.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/marker-block.js
type: application/javascript
module-type: wikirule

Block-level Custom-Markup parse rule. One rule for all block-invokable
markers (glyph, glyph-level, word). Reads from parser.cmRegistry.

\*/

"use strict";

exports.name = "cmblock";
exports.types = {block: true};

exports.init = function(parser) {
	this.parser = parser;
	if(!parser.cmRegistry) {
		parser.cmRegistry = new $tw.utils.CmRegistry(parser.wiki);
		// Load all known markers so the regex is comprehensive at init time
		// (avoids TW's rule-pruning when source has only later-activated
		// markers). Vocabulary scoping is enforced by the active-set check
		// in parse() below.
		parser.cmRegistry.loadAllMarkers();
		// Pull bridged symbols from PageTemplate's `\importcustom`-loaded
		// pragmas (v0.x global pragma equivalent). Recursion-guarded.
		parser.cmRegistry.loadGlobalPragmas();
		parser.cmRegistry.activateFromTypeField(parser.type);
		// Schedule the declared TW core-rule exclusions. The actual mutation
		// runs via a one-shot parsePragmas wrap (see registry.applyAmendRules
		// for why); init() is too early to amend rules safely.
		parser.cmRegistry.applyAmendRules(parser);
	}
	this.matchRegExp = parser.cmRegistry.getBlockRegex() || /(?!)/g;
};

// Override the default findNextMatch so that AFTER pragmas have parsed
// (so `\importcustom` has had its chance to activate vocabs), we skip
// over inactive marker positions instead of claiming them. Without this
// filter, an inactive marker whose open literal collides with a TW core
// rule (Vocab/Fountain's `#` SECTION vs core `list`, etc.) would silently
// eat the position via the text-fallback in parse(), suppressing the
// core rule for any tiddler in the wiki — even tiddlers that don't
// activate the offending vocab.
//
// Before pragmas: behave like the default (accept any marker match) so
// the rule survives TW's `instantiateRules` pruning and remains
// available for pragma-activated vocabs to use.
exports.findNextMatch = function(startPos) {
	var source = this.parser.source;
	var regex = this.matchRegExp;
	regex.lastIndex = startPos;
	var match;
	while((match = regex.exec(source)) !== null) {
		if(this.parser._cmPragmasDone) {
			var marker = identifyMarker(match[0], this.parser.cmRegistry);
			if(!marker || !this.parser.cmRegistry.isActive(marker.open)) {
				regex.lastIndex = match.index + 1;
				continue;
			}
		}
		this.match = match;
		return match.index;
	}
	this.match = null;
	return undefined;
};

exports.parse = function() {
	var registry = this.parser.cmRegistry;
	var matchText = this.match[0];
	var marker = identifyMarker(matchText, registry);
	if(!marker) {
		this.parser.pos = this.matchRegExp.lastIndex;
		return [];
	}
	// Vocabulary scoping: emit matched text as plain text if the marker's
	// open isn't in any active vocabulary for this parser.
	if(!registry.isActive(marker.open)) {
		this.parser.pos = this.matchRegExp.lastIndex;
		return [{type: "text", text: matchText}];
	}
	// List-item markers consume the whole list in one parse() call:
	// consecutive items collapse into a single container element, deeper
	// indent nests under the previous item, container switch starts a
	// sibling list. Body of each item parses as an inline run.
	if(marker.kind === "list-item") {
		return parseListItems(this.parser, this.match, this.matchRegExp);
	}
	var textStart = this.match.index;
	var parsed = parseMatchTail(matchText, marker);
	this.parser.pos = this.matchRegExp.lastIndex;
	this.parser.skipWhitespace({treatNewlinesAsNonWhitespace: true});
	var contentStart = this.parser.pos;
	var config = resolveConfig(marker, parsed.symbol, parsed.classes, parsed.level);
	config.quotedArgs = parsed.quotedArgs;
	var children = parseBody(this.parser, config);
	// Marker opts into keeping its open literal visible as body content
	// (Fountain transitions: `CUT TO:`, `FADE IN:`, ... where the keyword
	// IS the content). Add a trailing space when body has content so the
	// open literal and body don't run together (`INT. KITCHEN`, not
	// `INT.KITCHEN`); skipWhitespace eats the source-side separator before
	// body parsing begins, so we re-introduce it on the rendered side.
	if(marker.emitOpen === "yes") {
		children.unshift({type: "text", text: children.length > 0 ? marker.open + " " : marker.open});
	}
	var textEnd = this.parser.pos;
	var nodes = [];
	// `\debugmarker` pragma overrides the marker's static `debug` field for
	// this tiddler. `debugMarkerAllOff` is the wiki-wide off switch
	// (`\debugmarker no`); per-marker entries in `debugMarkerOverrides`
	// (including `=no`) win over the field.
	var effectiveDebug = resolveDebugMode(this.parser, marker.open, config.debug);
	if(effectiveDebug && effectiveDebug !== "no") {
		// Strip the trailing terminator (newline or blank-line) that
		// eatTerminator consumed, so the debug `text` codeblock matches
		// v0.x's clean per-marker source slice.
		var textOuter = this.parser.source.slice(textStart, textEnd).replace(/(?:\r?\n)+$/, "");
		nodes = nodes.concat(buildDebugNodes(effectiveDebug, config.debugString || "", textOuter));
	}
	if(!isDebugRenderSuppressed(effectiveDebug)) {
		nodes.push(buildNode(config, children, this.parser.source, contentStart, textEnd));
	}
	return nodes;
};

function resolveDebugMode(parser, open, fieldDebug) {
	if(parser.debugMarkerAllOff) { return "no"; }
	var overrides = parser.debugMarkerOverrides;
	if(overrides && Object.prototype.hasOwnProperty.call(overrides, open)) {
		return overrides[open];
	}
	return fieldDebug;
}

// `_debug` modes from v0.x (glyph-text.js / glyph-inline.js):
//   pragma (default), pragmaOnly, text, textOnly, both, no.
// `*Only` variants suppress the normal render. `both` shows both code blocks.
function buildDebugNodes(debug, debugString, textOuter) {
	var nodes = [];
	switch(debug) {
		case "both":
			nodes.push(codeblockNode(debugString));
			nodes.push(codeblockNode(textOuter));
			break;
		case "text":
		case "textOnly":
			nodes.push(codeblockNode(textOuter));
			break;
		case "pragmaOnly":
		case "pragma":
		default:
			nodes.push(codeblockNode(debugString));
	}
	return nodes;
}

function isDebugRenderSuppressed(debug) {
	return debug === "textOnly" || debug === "pragmaOnly";
}

function codeblockNode(text) {
	return {
		type: "codeblock",
		attributes: {code: {type: "string", value: text || ""}}
	};
}

function identifyMarker(matchText, registry) {
	var markers = registry.list();
	markers.sort(function(a, b) {
		// Word ahead of non-word; longest open first within each
		if(a.kind === "word" && b.kind !== "word") { return -1; }
		if(a.kind !== "word" && b.kind === "word") { return 1; }
		var aLen = a.kind === "list-item" ? (a.openPattern || a.open).length : a.open.length;
		var bLen = b.kind === "list-item" ? (b.openPattern || b.open).length : b.open.length;
		return bLen - aLen;
	});
	// list-item matches start with optional indent; strip it before testing
	// the bullet so e.g. "  - " resolves to the dash marker.
	var trimmed = matchText.replace(/^[ \t]+/, "");
	for(var i = 0; i < markers.length; i++) {
		var m = markers[i];
		if(m.kind === "list-item") {
			if(m.openPattern) {
				if(new RegExp("^(?:" + m.openPattern + ")").test(trimmed)) {
					return m;
				}
			} else if(trimmed.indexOf(m.open) === 0) {
				return m;
			}
		} else if(matchText.indexOf(m.open) === 0) {
			return m;
		}
	}
	return null;
}

// Consume a run of list-item matches into a nested tree of container
// elements. Each item's body is parsed as an inline run terminated by
// the next newline. Indent (after tab-expansion to indent-unit spaces)
// drives nesting level; container change at the same level starts a
// sibling list.
function parseListItems(parser, firstMatch, blockRegExp) {
	var registry = parser.cmRegistry;
	var roots = [];
	var stack = []; // [{listNode, container, level}]
	var sharedRe = new RegExp(blockRegExp.source, "mg");
	var match = firstMatch;

	while(match) {
		var marker = identifyMarker(match[0], registry);
		if(!marker || marker.kind !== "list-item" || !registry.isActive(marker.open)) { break; }

		var indentText = (/^[ \t]*/.exec(match[0]) || [""])[0];
		var indent = indentText.replace(/\t/g, repeatSpace(marker.indentUnit)).length;
		var level = Math.floor(indent / marker.indentUnit);
		if(level > stack.length) { level = stack.length; }

		while(stack.length > level + 1) { stack.pop(); }

		if(stack.length === level + 1 && stack[level].container !== marker.container) {
			stack.pop();
		}

		if(stack.length === level) {
			var newList = {type: "element", tag: marker.container, children: []};
			if(level === 0) {
				roots.push(newList);
			} else {
				var parentList = stack[level - 1].listNode;
				var parentItem = parentList.children[parentList.children.length - 1];
				parentItem.children.push(newList);
			}
			stack.push({listNode: newList, container: marker.container, level: level});
		}

		parser.pos = match.index + match[0].length;
		var bodyTree = parser.parseInlineRun(/(\r?\n)/mg, {eatTerminator: true});

		stack[level].listNode.children.push({
			type: "element",
			tag: marker.itemElement,
			children: bodyTree
		});

		sharedRe.lastIndex = parser.pos;
		var nextMatch = sharedRe.exec(parser.source);
		if(!nextMatch || nextMatch.index !== parser.pos) { break; }
		match = nextMatch;
	}

	return roots;
}

function repeatSpace(n) {
	var s = "";
	for(var i = 0; i < n; i++) { s += " "; }
	return s;
}

function parseMatchTail(matchText, marker) {
	var result = {level: 1, symbol: "", classes: [], quotedArgs: []};
	var pos = marker.open.length;
	if(marker.kind === "glyph-level") {
		while(matchText.substr(pos, marker.open.length) === marker.open) {
			result.level++;
			pos += marker.open.length;
		}
	}
	if((marker.kind === "glyph" || marker.kind === "glyph-level") && marker.allowSymbol) {
		var symMatch = /^[^.:\s]*/.exec(matchText.substr(pos));
		if(symMatch && symMatch[0].length > 0) {
			result.symbol = symMatch[0];
			pos += symMatch[0].length;
		}
	}
	while(matchText.charAt(pos) === ".") {
		var cMatch = /^\.([^.\s:]+)/.exec(matchText.substr(pos));
		if(cMatch) {
			result.classes.push(cMatch[1]);
			pos += cMatch[0].length;
		} else {
			break;
		}
	}
	while(matchText.charAt(pos) === ":" && matchText.charAt(pos + 1) === '"') {
		var qMatch = /^:"([^"]*)"/.exec(matchText.substr(pos));
		if(qMatch) {
			result.quotedArgs.push(qMatch[1]);
			pos += qMatch[0].length;
		} else {
			break;
		}
	}
	return result;
}

function resolveConfig(marker, symbol, classes, level) {
	var config = {
		marker: marker,
		symbol: symbol,
		level: level,
		mode: marker.mode,
		// Block-position fires (this rule) always wrap in a block element.
		// `mode: inline` controls how the body is parsed (single line vs
		// multi-block); it doesn't change the container element type.
		element: marker.element || "div",
		endString: marker.endString,
		classes: marker.classes || "",
		attributes: marker.attributes || {},
		srcName: marker.srcName,
		userClasses: classes,
		// Marker-tiddler `debug` / `debug-string` fields. Symbol resolution
		// (applySymbolToConfig) can still override these with `_use` / legacy
		// `_debug` values from a pragma symbol.
		debug: marker.debug || "",
		debugString: marker.debugString || ""
	};
	var sym = lookupSymbol(marker, symbol);
	if(sym) {
		// Follow `_use` / `_useGlobal` aliases. Errors are surfaced via
		// the debug-codeblock path in parse().
		sym = followUse(marker, sym);
		applySymbolToConfig(config, sym);
	} else if(symbol && marker.allowSymbol) {
		// HTML-element fallback: any HTML element name overrides the default
		var cmInline = ($tw.config.cmInlineElements || []).indexOf(symbol) !== -1;
		var cmBlock = ($tw.config.cmBlockElements || []).indexOf(symbol) !== -1;
		if(cmBlock || cmInline) {
			config.element = symbol;
			if(cmBlock) { config.mode = "block"; }
		}
	}
	return config;
}

function lookupSymbol(marker, symbol) {
	if(marker.symbols && marker.symbols[symbol]) { return marker.symbols[symbol]; }
	if(marker.globalSymbols && marker.globalSymbols[symbol]) { return marker.globalSymbols[symbol]; }
	return null;
}

// Resolve `_use` (local-only alias) and `_useGlobal` (global-only alias)
// chains. v0.x semantics:
//   _use: extend target with the local pragma's overrides (local wins).
//   _useGlobal: switch to target wholesale; only the local `_debug` value
//     wins (forceDebug). Target's `_debugString` is shown so the debug
//     output reveals what config is actually applied.
function followUse(marker, sym) {
	if(sym.use) {
		var localTarget = marker.symbols && marker.symbols[sym.use];
		if(localTarget) {
			return mergeSymbol(localTarget, sym, "use");
		}
		return $tw.utils.extend({}, sym, {
			debug: sym.debug || "pragma",
			debugString: "Error - \\custom " + (marker.legacyKind || marker.open) + "=" + sym.use + " is not defined!"
		});
	}
	if(sym.useGlobal) {
		var globalTarget = marker.globalSymbols && marker.globalSymbols[sym.useGlobal];
		if(globalTarget) {
			var merged = $tw.utils.extend({}, globalTarget);
			delete merged.useGlobal;
			// Local `_debug` wins (v0.x's forceDebug capture).
			if(sym.debug) { merged.debug = sym.debug; }
			return merged;
		}
		return $tw.utils.extend({}, sym, {
			debug: sym.debug || "pragma",
			debugString: "Error - global \\custom " + (marker.legacyKind || marker.open) + "=" + sym.useGlobal + " is not defined!"
		});
	}
	return sym;
}

// Merge target onto sym (sym's overrides win), dropping the `use` / `useGlobal`
// field so we don't re-follow on a subsequent resolveConfig pass.
function mergeSymbol(target, sym, useField) {
	var merged = $tw.utils.extend({}, target, sym);
	delete merged[useField];
	// Attributes from both sides should compose, not overwrite.
	if(target.attributes && sym.attributes) {
		merged.attributes = $tw.utils.extend({}, target.attributes, sym.attributes);
	}
	return merged;
}

function applySymbolToConfig(config, sym) {
	if(sym.element) { config.element = sym.element; }
	if(sym.endString !== undefined) { config.endString = sym.endString; }
	if(sym.classes) { config.classes = config.classes + sym.classes; }
	if(sym.mode) { config.mode = sym.mode; }
	if(sym.srcName) { config.srcName = sym.srcName; }
	if(sym.attributes) { config.attributes = $tw.utils.extend({}, config.attributes, sym.attributes); }
	if(sym.params) { config.params = sym.params; }
	if(sym.debug) { config.debug = sym.debug; }
	if(sym.debugString) { config.debugString = sym.debugString; }
}

// paragraph-marker: explicit schema flag. "yes" opts into paragraph
// terminator (blank line); anything else is non-paragraph (single newline).
function isParagraphMarker(marker) {
	return !!marker && marker.paragraphMarker === "yes";
}

function parseBody(parser, config) {
	if(config.mode === "block") {
		// Explicit endString wins regardless of wrapper element. Browser
		// auto-closes `<p>` when block children appear inside, matching
		// v0.x's parseBlocks-with-newline-terminator behaviour.
		if(config.endString) {
			return parser.parseBlocks($tw.utils.escapeRegExp(unescapeEndString(config.endString)));
		}
		// `<p>` wrapper without explicit endString: parse body inline so the
		// paragraph wrapper doesn't nest an inner paragraph. This is a DOM
		// constraint on the rendered element, not the marker's paragraph-ness.
		if(config.element === "p") {
			return parser.parseInlineRun(/(\r?\n\r?\n)/mg, {eatTerminator: true});
		}
		// Non-paragraph markers (´, °, › and any marker with paragraph-marker:no
		// or undefined+element!=p) default to single-newline terminator so each
		// fire on its own line is a separate node. Paragraph markers fall through
		// to blank-line default.
		if(config.marker && !isParagraphMarker(config.marker)) {
			return parser.parseBlock("\\r?\\n");
		}
		return parser.parseBlock();
	}
	// mode === "inline": pick terminator by marker's paragraph-ness. v0.x's
	// useParagraph markers (», ≈, ¶) terminate at a blank line; the rest (´, °, ›)
	// terminate at single newline. The paragraph-marker field is the canonical
	// signal; element===p is the back-compat fallback.
	var terminator;
	if(config.endString) {
		terminator = new RegExp("(" + $tw.utils.escapeRegExp(unescapeEndString(config.endString)) + ")", "mg");
	} else if(config.marker && isParagraphMarker(config.marker)) {
		terminator = /(\r?\n\r?\n)/mg;
	} else {
		terminator = /(\r?\n)/mg;
	}
	return parser.parseInlineRun(terminator, {eatTerminator: true});
}

// TW's parseAttribute returns `_endString="\n"` as the literal two-char
// string `\n`. Unescape JS-style sequences so users can write `"\n"`,
// `"\r\n"`, `"\t"` and have them mean what they look like.
function unescapeEndString(s) {
	if(typeof s !== "string") { return s; }
	return s.replace(/\\([nrt\\'"])/g, function(_, c) {
		switch(c) {
			case "n": return "\n";
			case "r": return "\r";
			case "t": return "\t";
			case "\\": return "\\";
			case "'": return "'";
			case '"': return '"';
		}
		return c;
	});
}

function buildNode(config, children, source, contentStart, parserPos) {
	var classes = [];
	if(config.classes) {
		$tw.utils.each(config.classes.split("."), function(c) {
			if(c) { classes.push(c); }
		});
	}
	if(config.userClasses && config.userClasses.length) {
		classes = classes.concat(config.userClasses);
	}
	if(config.level && config.marker && config.marker.kind === "glyph-level") {
		classes.push("wltc-l" + config.level);
	}
	classes.push("wltc");
	var attrs = {
		"class": {type: "string", value: classes.join(" ").trim()}
	};
	if(config.attributes) {
		for(var key in config.attributes) {
			if(key !== "class") {
				attrs[key] = toAttrNode(config.attributes[key]);
			}
		}
	}
	if(config.params && config.params.length > 0) {
		var args = config.quotedArgs || [];
		for(var i = 0; i < config.params.length; i++) {
			var p = config.params[i];
			if(!p || !p.name) { continue; }
			var override = args[i];
			if(typeof override === "string" && override.length > 0) {
				attrs[p.name] = {type: "string", value: override};
			} else {
				attrs[p.name] = toAttrNode(p);
			}
		}
	}
	if(config.element.charAt(0) === "$") {
		var contentEnd = parserPos;
		if(config.endString) { contentEnd -= config.endString.length; }
		var innerText = source.substring(contentStart, contentEnd);
		// Strip trailing line-endings consumed by the implicit terminator
		// (eatTerminator on inline mode, or the blank-line terminator on
		// block-with-paragraph wrapping). Otherwise widget attributes pick
		// up stray "\n" — which becomes "%0A" in URL-valued attrs.
		if(!config.endString) {
			innerText = innerText.replace(/(?:\r?\n)+$/, "");
		}
		attrs[config.srcName || "src"] = {type: "string", value: innerText};
		return {
			type: config.element.substr(1),
			tag: config.element,
			attributes: attrs,
			children: children
		};
	}
	return {
		type: "element",
		tag: config.element,
		attributes: attrs,
		children: children
	};
}

// Convert a parseAttribute token (or a plain string) into a parse-tree
// attribute node. Preserves indirect / macro / filtered / substituted
// types so `{{!!field}}`, `<<macro>>`, and `{{{filter}}}` survive into
// the rendered widget instead of being stringified to "[object Object]".
function toAttrNode(token) {
	if(token === null || token === undefined) {
		return {type: "string", value: ""};
	}
	if(typeof token === "string") {
		return {type: "string", value: token};
	}
	switch(token.type) {
		case "indirect":
			return {type: "indirect", textReference: token.textReference};
		case "macro":
			return {type: "macro", value: token.value};
		case "filtered":
			return {type: "filtered", filter: token.filter};
		case "substituted":
			return {type: "substituted", rawValue: token.rawValue};
		case "string":
		default:
			return {type: "string", value: (token.value !== undefined) ? String(token.value) : ""};
	}
}
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/marker-inline.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/marker-inline.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/marker-inline.js
type: application/javascript
module-type: wikirule

Inline-level Custom-Markup parse rule. Handles inline-pair kind (paired
open/close literals like /° °/, ❮ ❯, ⠒ ⠶). Reads from parser.cmRegistry.

\*/

"use strict";

exports.name = "cminline";
exports.types = {inline: true};

exports.init = function(parser) {
	this.parser = parser;
	if(!parser.cmRegistry) {
		parser.cmRegistry = new $tw.utils.CmRegistry(parser.wiki);
		// See marker-block.js for why all markers are loaded at init.
		parser.cmRegistry.loadAllMarkers();
		parser.cmRegistry.loadGlobalPragmas();
		parser.cmRegistry.activateFromTypeField(parser.type);
		parser.cmRegistry.applyAmendRules(parser);
	}
	this.matchRegExp = parser.cmRegistry.getInlineRegex() || /(?!)/g;
};

// See marker-block.js findNextMatch override for the rationale. Same
// pattern: filter inactive marker positions once pragmas have parsed,
// so inline-pair markers in vocabs the tiddler hasn't activated don't
// shadow TW core rules.
exports.findNextMatch = function(startPos) {
	var source = this.parser.source;
	var regex = this.matchRegExp;
	regex.lastIndex = startPos;
	var match;
	while((match = regex.exec(source)) !== null) {
		if(this.parser._cmPragmasDone) {
			var marker = identifyInlinePairMarker(match[0], this.parser.cmRegistry);
			if(!marker || !this.parser.cmRegistry.isActive(marker.open)) {
				regex.lastIndex = match.index + 1;
				continue;
			}
		}
		this.match = match;
		return match.index;
	}
	this.match = null;
	return undefined;
};

exports.parse = function() {
	var registry = this.parser.cmRegistry;
	var matchText = this.match[0];
	var marker = identifyInlinePairMarker(matchText, registry);
	if(!marker) {
		this.parser.pos = this.matchRegExp.lastIndex;
		return [];
	}
	// Vocabulary scoping: emit matched text as plain text if the marker's
	// open isn't in any active vocabulary for this parser.
	if(!registry.isActive(marker.open)) {
		this.parser.pos = this.matchRegExp.lastIndex;
		return [{type: "text", text: matchText}];
	}
	var textStart = this.match.index;
	var parsed = parseMatchTail(matchText, marker);
	this.parser.pos = this.matchRegExp.lastIndex;
	this.parser.skipWhitespace({treatNewlinesAsNonWhitespace: true});
	var contentStart = this.parser.pos;
	var config = resolveConfig(marker, parsed.symbol, parsed.classes);
	config.quotedArgs = parsed.quotedArgs;
	var children = parseBody(this.parser, config);
	var textEnd = this.parser.pos;
	var nodes = [];
	// See marker-block.js for the override resolution rationale.
	var effectiveDebug = resolveDebugMode(this.parser, marker.open, config.debug);
	if(effectiveDebug && effectiveDebug !== "no") {
		var textOuter = this.parser.source.slice(textStart, textEnd).replace(/(?:\r?\n)+$/, "");
		nodes = nodes.concat(buildDebugNodes(effectiveDebug, config.debugString || "", textOuter));
	}
	if(!isDebugRenderSuppressed(effectiveDebug)) {
		nodes.push(buildNode(config, children, this.parser.source, contentStart, textEnd));
	}
	return nodes;
};

function resolveDebugMode(parser, open, fieldDebug) {
	if(parser.debugMarkerAllOff) { return "no"; }
	var overrides = parser.debugMarkerOverrides;
	if(overrides && Object.prototype.hasOwnProperty.call(overrides, open)) {
		return overrides[open];
	}
	return fieldDebug;
}

function buildDebugNodes(debug, debugString, textOuter) {
	var nodes = [];
	switch(debug) {
		case "both":
			nodes.push(codeblockNode(debugString));
			nodes.push(codeblockNode(textOuter));
			break;
		case "text":
		case "textOnly":
			nodes.push(codeblockNode(textOuter));
			break;
		case "pragmaOnly":
		case "pragma":
		default:
			nodes.push(codeblockNode(debugString));
	}
	return nodes;
}

function isDebugRenderSuppressed(debug) {
	return debug === "textOnly" || debug === "pragmaOnly";
}

function codeblockNode(text) {
	return {
		type: "codeblock",
		attributes: {code: {type: "string", value: text || ""}}
	};
}

function identifyInlinePairMarker(matchText, registry) {
	var markers = registry.list(function(m) { return m.kind === "inline-pair"; });
	markers.sort(function(a, b) { return b.open.length - a.open.length; });
	for(var i = 0; i < markers.length; i++) {
		if(matchText.indexOf(markers[i].open) === 0) {
			return markers[i];
		}
	}
	return null;
}

function parseMatchTail(matchText, marker) {
	var result = {symbol: "", classes: [], quotedArgs: []};
	var pos = marker.open.length;
	var symMatch = /^[^.:\s]*/.exec(matchText.substr(pos));
	if(symMatch && symMatch[0].length > 0) {
		result.symbol = symMatch[0];
		pos += symMatch[0].length;
	}
	while(matchText.charAt(pos) === ".") {
		var cMatch = /^\.([^.\s:]+)/.exec(matchText.substr(pos));
		if(cMatch) {
			result.classes.push(cMatch[1]);
			pos += cMatch[0].length;
		} else {
			break;
		}
	}
	while(matchText.charAt(pos) === ":" && matchText.charAt(pos + 1) === '"') {
		var qMatch = /^:"([^"]*)"/.exec(matchText.substr(pos));
		if(qMatch) {
			result.quotedArgs.push(qMatch[1]);
			pos += qMatch[0].length;
		} else {
			break;
		}
	}
	return result;
}

function resolveConfig(marker, symbol, classes) {
	var config = {
		marker: marker,
		symbol: symbol,
		mode: marker.mode,
		element: marker.element || (marker.mode === "block" ? "div" : "span"),
		close: marker.close,
		classes: marker.classes || "",
		attributes: marker.attributes || {},
		srcName: marker.srcName,
		userClasses: classes,
		bodyRaw: marker.bodyRaw,
		// See marker-block.js for the rationale on propagating debug fields.
		debug: marker.debug || "",
		debugString: marker.debugString || ""
	};
	var sym = lookupSymbol(marker, symbol);
	if(sym) {
		sym = followUse(marker, sym);
		applySymbolToConfig(config, sym);
	} else if(symbol) {
		// HTML-element fallback: any HTML element name overrides the default
		var cmInline = ($tw.config.cmInlineElements || []).indexOf(symbol) !== -1;
		var cmBlock = ($tw.config.cmBlockElements || []).indexOf(symbol) !== -1;
		if(cmBlock || cmInline) {
			config.element = symbol;
		}
	}
	return config;
}

function lookupSymbol(marker, symbol) {
	if(marker.symbols && marker.symbols[symbol]) { return marker.symbols[symbol]; }
	if(marker.globalSymbols && marker.globalSymbols[symbol]) { return marker.globalSymbols[symbol]; }
	return null;
}

function followUse(marker, sym) {
	if(sym.use) {
		var localTarget = marker.symbols && marker.symbols[sym.use];
		if(localTarget) { return mergeSymbol(localTarget, sym, "use"); }
		return $tw.utils.extend({}, sym, {
			debug: sym.debug || "pragma",
			debugString: "Error - \\custom " + (marker.legacyKind || marker.open) + "=" + sym.use + " is not defined!"
		});
	}
	if(sym.useGlobal) {
		// _useGlobal switches to target wholesale (v0.x semantics).
		// Only local _debug wins (forceDebug); target's _debugString shows.
		var globalTarget = marker.globalSymbols && marker.globalSymbols[sym.useGlobal];
		if(globalTarget) {
			var merged = $tw.utils.extend({}, globalTarget);
			delete merged.useGlobal;
			if(sym.debug) { merged.debug = sym.debug; }
			return merged;
		}
		return $tw.utils.extend({}, sym, {
			debug: sym.debug || "pragma",
			debugString: "Error - global \\custom " + (marker.legacyKind || marker.open) + "=" + sym.useGlobal + " is not defined!"
		});
	}
	return sym;
}

function mergeSymbol(target, sym, useField) {
	var merged = $tw.utils.extend({}, target, sym);
	delete merged[useField];
	if(target.attributes && sym.attributes) {
		merged.attributes = $tw.utils.extend({}, target.attributes, sym.attributes);
	}
	return merged;
}

function applySymbolToConfig(config, sym) {
	if(sym.element) { config.element = sym.element; }
	if(sym.classes) { config.classes = config.classes + sym.classes; }
	if(sym.mode) { config.mode = sym.mode; }
	if(sym.srcName) { config.srcName = sym.srcName; }
	if(sym.attributes) { config.attributes = $tw.utils.extend({}, config.attributes, sym.attributes); }
	if(sym.params) { config.params = sym.params; }
	if(sym.debug) { config.debug = sym.debug; }
	if(sym.debugString) { config.debugString = sym.debugString; }
}

function parseBody(parser, config) {
	if(config.bodyRaw) {
		// Literal-text body: capture everything between open and close
		// verbatim as a single text node, no recursive parsing. Used for
		// code spans, escape regions, raw-HTML quoting — any inline-pair
		// where the body must be preserved as-is.
		var closeIdx = parser.source.indexOf(config.close, parser.pos);
		if(closeIdx === -1) {
			// No close found — consume to end of source.
			closeIdx = parser.source.length;
		}
		var bodyText = parser.source.substring(parser.pos, closeIdx);
		parser.pos = closeIdx + config.close.length;
		return [{type: "text", text: bodyText}];
	}
	if(config.mode === "block") {
		return parser.parseBlocks($tw.utils.escapeRegExp(config.close));
	}
	var closeRe = new RegExp("(" + $tw.utils.escapeRegExp(config.close) + ")", "mg");
	return parser.parseInlineRun(closeRe, {eatTerminator: true});
}

function buildNode(config, children, source, contentStart, parserPos) {
	var classes = [];
	if(config.classes) {
		$tw.utils.each(config.classes.split("."), function(c) {
			if(c) { classes.push(c); }
		});
	}
	if(config.userClasses && config.userClasses.length) {
		classes = classes.concat(config.userClasses);
	}
	classes.push("wltc");
	var attrs = {
		"class": {type: "string", value: classes.join(" ").trim()}
	};
	if(config.attributes) {
		for(var key in config.attributes) {
			if(key !== "class") {
				attrs[key] = toAttrNode(config.attributes[key]);
			}
		}
	}
	if(config.params && config.params.length > 0) {
		var args = config.quotedArgs || [];
		for(var i = 0; i < config.params.length; i++) {
			var p = config.params[i];
			if(!p || !p.name) { continue; }
			var override = args[i];
			if(typeof override === "string" && override.length > 0) {
				attrs[p.name] = {type: "string", value: override};
			} else {
				attrs[p.name] = toAttrNode(p);
			}
		}
	}
	if(config.element.charAt(0) === "$") {
		var contentEnd = parserPos - (config.close ? config.close.length : 0);
		var innerText = source.substring(contentStart, contentEnd);
		attrs[config.srcName || "src"] = {type: "string", value: innerText};
		return {
			type: config.element.substr(1),
			tag: config.element,
			attributes: attrs,
			children: children
		};
	}
	return {
		type: "element",
		tag: config.element,
		attributes: attrs,
		children: children
	};
}

// Convert a parseAttribute token (or plain string) into a parse-tree
// attribute node, preserving indirect / macro / filtered / substituted
// types so `{{!!field}}`, `<<macro>>`, etc. don't get stringified.
function toAttrNode(token) {
	if(token === null || token === undefined) {
		return {type: "string", value: ""};
	}
	if(typeof token === "string") {
		return {type: "string", value: token};
	}
	switch(token.type) {
		case "indirect":
			return {type: "indirect", textReference: token.textReference};
		case "macro":
			return {type: "macro", value: token.value};
		case "filtered":
			return {type: "filtered", filter: token.filter};
		case "substituted":
			return {type: "substituted", rawValue: token.rawValue};
		case "string":
		default:
			return {type: "string", value: (token.value !== undefined) ? String(token.value) : ""};
	}
}
