title: $:/plugins/wikilabs/custom-markup/wikirules/custom.js
type: application/javascript
module-type: wikirule

Wiki pragma rule for Custom-Markup configuration.

```
\custom tick=§ _element=div _endString= _mode= _classes= _use=
\custom angle=x _element=span _classes=.i.j.c.cp _endString=eee
\custom single=det _element="details" _classes="" _endString="—"
\custom degree=sum _element="summary"
\custom tick _element=span
```

\*/

"use strict";

exports.name = "custom";
exports.types = {pragma: true};

var idTypes = ["tick", "single", "degree", "angle", "approx", "pilcrow", "corner", "braille", "slash"];

exports.init = function(parser) {
	var self = this;
	this.parser = parser;
	this.matchRegExp = /^\\custom[^\S\n]/mg;

	this.p = this.parser;
	this.p.configTickText = this.p.configTickText || {};
	this.pc = this.p.configTickText;

	idTypes.forEach(function(id) {
		self.pc[id] = self.pc[id] || {};
	});
};

function parseAttributes(source) {
	var pos = 0,
		attributes = [];
	var attribute = $tw.utils.parseAttribute(source, pos);
	while(attribute) {
		attributes.push(attribute);
		pos = attribute.end;
		attribute = $tw.utils.parseAttribute(source, pos);
	}
	return attributes;
}

exports.parse = function() {
	this.parser.pos = this.matchRegExp.lastIndex;
	// Read the rest of the line
	var reMatch = /([^\n]*\S)|(\r?\n)/mg,
		line = "";
	reMatch.lastIndex = this.parser.pos;
	var match = reMatch.exec(this.parser.source);
	while(match && match.index === this.parser.pos) {
		this.parser.pos = reMatch.lastIndex;
		if(match[2]) { break; }
		if(match[1]) { line = match[1]; }
		match = reMatch.exec(this.parser.source);
	}

	var attributes = parseAttributes(line);

	var id = "X",
		configTickText = {},
		debugString = "\\custom";

	$tw.utils.each(attributes, function(token) {
		if(idTypes.indexOf(token.name) >= 0) {
			id = token.name;
			configTickText.symbol = token.value;
			debugString += " " + id + "='" + token.value + "'";
			// Kind-name token is structural; don't fall through to the default
			// switch arm, which would store it as a passthrough attribute.
			return;
		}
		switch(token.name) {
			case "_classes":
			case "_debug":
			case "_mode":
			case "_element":
			case "_endString":
			case "_use":
			case "_useGlobal":
			case "_srcName":
				configTickText[token.name] = token.value;
				debugString += " " + token.name + "='" + token.value + "'";
				break;
			case "_params":
				configTickText[token.name] = parseAttributes(token.value);
				debugString += " " + token.name + "='" + token.value + "'";
				break;
			default:
				configTickText[token.name] = token || {};
				var tValue = (token.type === "macro") ? "<<" + token.value.name + ">>"
					: (token.type === "indirect") ? "{{" + token.textReference + "}}"
					: "'" + token.value + "'";
				debugString += " " + token.name + "=" + tValue;
		}
	});

	configTickText._debugString = debugString;
	// Unknown kind names (e.g. \custom X _element=p — anything outside
	// idTypes) need an init step or the legacy pc[id][symbol] assignment
	// would throw "Cannot set properties of undefined".
	this.pc[id] = this.pc[id] || {};
	this.pc[id][configTickText.symbol] = configTickText;

	// Bridge to new vocabulary registry. No-op if cmRegistry is absent or
	// has no marker matching this kind/open. Lets `\custom degree=foo`
	// register on the ° marker once Vocab/Default ships.
	if(this.parser.cmRegistry && typeof this.parser.cmRegistry.bridgeLegacyConfig === "function") {
		this.parser.cmRegistry.bridgeLegacyConfig(id, configTickText);
	}

	return [];
};
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/pragmas/debug-custom.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/pragmas/debug-custom.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/pragmas/debug-custom.js
type: application/javascript
module-type: wikirule

Returns a JSON dump of parser.configTickText (the legacy registry) plus
parser.cmRegistry.markers (the v1 marker registry).

```
\debugcustom
\debugcustom list
\debugcustom global
\debugcustom global list
\debugcustom global <id-or-open>
\debugcustom <id-or-open>
\debugcustom no
```

`<id>` matches a legacy kind (tick, single, degree, angle, approx, pilcrow,
corner, braille, slash). `<open>` matches any v1 marker's `open` literal
(e.g. `.`, `»`, `PRESENTATION`). Word-marker opens with whitespace are
supported via the joined tail of arguments.

\*/

"use strict";

exports.name = "debugcustom";
exports.types = {pragma: true};

// Legacy 9-kind list — pre-populated on configTickText so v0.x
// pragmas (`\custom degree=foo`) and v0.x debugcustom usage continue to work.
var legacyKinds = ["tick", "single", "degree", "angle", "approx", "pilcrow", "corner", "braille", "slash"];

exports.init = function(parser) {
	var self = this;
	this.parser = parser;
	this.matchRegExp = /^\\debugcustom[^\S\n]/mg;

	this.p = this.parser;
	this.p.configTickText = this.p.configTickText || {};
	this.pc = this.p.configTickText;

	legacyKinds.forEach(function(id) {
		self.pc[id] = self.pc[id] || {};
	});
};

exports.parse = function() {
	this.parser.pos = this.matchRegExp.lastIndex;
	var reMatch = /(.*)\r?\n?|$/mg;
	reMatch.lastIndex = this.parser.pos;
	var match = reMatch.exec(this.parser.source);
	this.parser.pos = reMatch.lastIndex;

	var localConfig = this.pc,
		localMarkers = (this.p.cmRegistry && this.p.cmRegistry.markers) || {},
		globalParser = this.p.wiki.parseTiddler("$:/config/custom-markup/pragma/PageTemplate"),
		globalConfig = (globalParser && globalParser.configTickText) || {},
		globalMarkers = (globalParser && globalParser.cmRegistry && globalParser.cmRegistry.markers) || {};

	legacyKinds.forEach(function(id) { globalConfig[id] = globalConfig[id] || {}; });

	var tokens = (match[0] === "" || !match[1]) ? [""] : match[1].split(/[ \t]+/);
	var first = tokens[0] || "";

	var text = "";
	if(first === "no") {
		return [];
	} else if(first === "global") {
		var globalArg = tokens.slice(1).join(" ");
		text = renderScope("global", globalArg, globalConfig, globalMarkers);
	} else {
		var localArg = tokens.join(" ");
		text = renderScope("local", localArg, localConfig, localMarkers);
	}

	return [{
		type: "codeblock",
		attributes: {
			code: {type: "string", value: text}
		}
	}];
};

function renderScope(scope, arg, config, markers) {
	if(arg === "list") {
		return renderList(scope, config, markers);
	}
	if(arg === "" || arg === "all") {
		return renderAll(scope, config, markers);
	}
	return renderLookup(scope, arg, config, markers);
}

function renderList(scope, config, markers) {
	var text = scope + " list:\n";

	text += "  legacy kinds:\n";
	var legacyFound = false;
	legacyKinds.forEach(function(kind) {
		var bucket = config[kind] || {};
		if(Object.keys(bucket).length > 0) {
			text += "    - " + kind + " {..}\n";
			legacyFound = true;
		}
	});
	if(!legacyFound) {
		text += "    (no keys with values found)\n";
	}

	text += "  markers:\n";
	var opens = Object.keys(markers);
	if(opens.length === 0) {
		text += "    (none)\n";
	} else {
		opens.sort();
		opens.forEach(function(open) {
			var m = markers[open];
			var symbolCount = m.symbols ? Object.keys(m.symbols).length : 0;
			var hints = ["kind=" + m.kind];
			if(m.legacyKind) { hints.push("legacy-kind=" + m.legacyKind); }
			if(symbolCount > 0) {
				hints.push(symbolCount + (symbolCount === 1 ? " symbol" : " symbols"));
			}
			text += "    - " + open + "  (" + hints.join(", ") + ")\n";
		});
	}
	return text;
}

function renderAll(scope, config, markers) {
	return scope + " all:\n" + JSON.stringify(config, null, 2) + "\n" +
		scope + " markers:\n" + JSON.stringify(serializeMarkers(markers), null, 2) + "\n";
}

function renderLookup(scope, key, config, markers) {
	// Legacy kind lookup keeps v0.x output shape byte-for-byte.
	if(legacyKinds.indexOf(key) !== -1) {
		return scope + " " + key + ":\n" + JSON.stringify(config[key] || {}, null, 2) + "\n";
	}
	if(markers[key]) {
		return scope + " " + key + ":\n" + JSON.stringify(serializeMarker(markers[key]), null, 2) + "\n";
	}
	return scope + " " + key + ": (not found)\n";
}

function serializeMarkers(markers) {
	var out = {};
	Object.keys(markers).forEach(function(open) {
		out[open] = serializeMarker(markers[open]);
	});
	return out;
}

function serializeMarker(marker) {
	var out = {};
	Object.keys(marker).forEach(function(key) {
		// globalSymbols is a cross-parser reference to the global registry's
		// symbols map; including it would duplicate the global view.
		if(key === "globalSymbols") { return; }
		out[key] = marker[key];
	});
	return out;
}
","type":"application/javascript","module-type":"wikirule"},"$:/plugins/wikilabs/custom-markup/wikirules/pragmas/debug-marker.js":{"title":"$:/plugins/wikilabs/custom-markup/wikirules/pragmas/debug-marker.js","text":"/*\
title: $:/plugins/wikilabs/custom-markup/wikirules/pragmas/debug-marker.js
type: application/javascript
module-type: wikirule

Per-tiddler override for a v1 marker's render-time debug mode. Parallels
v0.x's `_debug` pragma attribute, scoped to the tiddler the pragma lives in.

```
\debugmarker <open>=<mode>     // turn on debug for this marker
\debugmarker <open>=no         // explicitly off (overrides the field)
\debugmarker no                // off for ALL markers in this tiddler
```

Modes: `pragma` (default if truthy), `pragmaOnly`, `text`, `textOnly`,
`both`, `no`. `<open>` matches either a marker's `open` literal or its
`legacy-kind` (so `\debugmarker tick=both` and `\debugmarker °=both` both
target the DEGREE marker).

\*/

"use strict";

exports.name = "debugmarker";
exports.types = {pragma: true};

exports.init = function(parser) {
	this.parser = parser;
	this.matchRegExp = /^\\debugmarker[^\S\n]/mg;
};

exports.parse = function() {
	this.parser.pos = this.matchRegExp.lastIndex;
	var reMatch = /(.*)\r?\n?|$/mg;
	reMatch.lastIndex = this.parser.pos;
	var match = reMatch.exec(this.parser.source);
	this.parser.pos = reMatch.lastIndex;

	var arg = ((match && match[1]) || "").trim();

	if(!this.parser.debugMarkerOverrides) {
		this.parser.debugMarkerOverrides = Object.create(null);
	}

	if(arg === "" || arg === "no") {
		this.parser.debugMarkerAllOff = true;
		return [];
	}

	// Split on LAST `=` so an open literal containing `=` still parses
	// correctly (mode-name set is fixed and contains no `=`).
	var eqIdx = arg.lastIndexOf("=");
	if(eqIdx === -1) { return []; }

	var open = arg.slice(0, eqIdx).trim();
	var mode = arg.slice(eqIdx + 1).trim();
	if(!open) { return []; }

	// Resolve `legacy-kind` aliases (tick, degree, ...) to the underlying
	// open literal so the marker-block / marker-inline override lookup
	// (keyed by `marker.open`) hits.
	var registry = this.parser.cmRegistry;
	if(registry && !registry.markers[open] && registry.findByOpenOrLegacyKind) {
		var byLegacy = registry.findByOpenOrLegacyKind(open);
		if(byLegacy && byLegacy.open) { open = byLegacy.open; }
	}

	this.parser.debugMarkerOverrides[open] = mode;
	return [];
};
